if.script:
try {
    def conn = new java.net.URL('https://open.er-api.com/v6/latest/' + fromCurrencyUomId).openConnection()
    conn.connectTimeout = 10000
    conn.readTimeout = 10000
    conn.setRequestProperty('Accept', 'application/json')
    def rates = new groovy.json.JsonSlurper().parseText(conn.inputStream.getText('UTF-8'))?.rates
    def rate = rates ? rates[toCurrencyUomId] : null
    if (rate) apiExchangeRate = rate as BigDecimal
} catch (Exception e) {
    ec.logger.warn("Exchange rate API call failed: ${e.message}")
}

actions.script:
def token = new org.apache.shiro.authc.UsernamePasswordToken(
    (String) userAccount.username, (String) oldPassword)
def info = new org.apache.shiro.authc.SimpleAuthenticationInfo(
    userAccount.username, userAccount.currentPassword,
    new org.apache.shiro.lang.util.SimpleByteSource(
        (String) (userAccount.passwordSalt ?: '')), "moquiRealm")

def restXml = new groovy.xml.XmlSlurper().parse(
    ec.resource.getLocationReference('component://growerp/service/growerp.rest.xml').openStream())
externalServiceNames = restXml.'**'.findAll { it.name() == 'service' }
    .collect { it.@name.text() } as Set

def llmConfigs = []
for (def lc in llmConfigList) {
    llmConfigs.add([llmProvider: lc.llmProvider, apiKey: lc.apiKey ? '****' : ''])
}
systemSettings.llmConfigs = llmConfigs

if.script:
def llmKeyChanged = false
def incomingProviders = llmConfigs.collect { it.llmProvider } as Set
for (def elc in existingLlmList) {
    if (!incomingProviders.contains(elc.llmProvider)) { elc.delete(); llmKeyChanged = true }
}
for (def lc in llmConfigs) {
    if (!lc.llmProvider) continue
    def existing = ec.entity.find('growerp.general.LlmConfig')
        .condition('ownerPartyId', ownerPartyId)
        .condition('llmProvider', lc.llmProvider).one()
    if (existing) {
        if (lc.apiKey && lc.apiKey != '****') {
            existing.apiKey = lc.apiKey
            existing.update()
            llmKeyChanged = true
        }
    } else {
        def newLc = ec.entity.makeValue('growerp.general.LlmConfig')
        newLc.ownerPartyId = ownerPartyId
        newLc.llmProvider  = lc.llmProvider
        if (lc.apiKey && lc.apiKey != '****') newLc.apiKey = lc.apiKey
        newLc.create()
        llmKeyChanged = true
    }
}
ec.context.llmKeyChanged = llmKeyChanged
